model Event { id String @id @default(uuid()) cityId String schoolId String crewId String? project String date DateTime time String? status EventStatus @default(BASE) childrenPlanned Int? childrenActual Int? price Float? received Float? paymentMethod String? address String? contactPerson String? contactPhone String? equipment String? nextContact DateTime? nextProject String? responsibleId String? createdAt DateTime @default(now()) updatedAt DateTime @updatedAt city City @relation(fields: [cityId], references: [id]) crew Crew? @relation(fields: [crewId], references: [id]) school School @relation(fields: [schoolId], references: [id]) history EventHistory[] preparation EventPreparation? report EventReport? files File[] issues IssueReport[]
@@index([cityId]) @@index([status]) @@index([schoolId]) }
