import { Injectable } from '@nestjs/common';
import { PrismaService } from 'src/prisma/prisma.service';

@Injectable()
export class CitiesService {
  constructor(private prisma: PrismaService) {}

  async create(name: string) {
    return this.prisma.city.create({
      data: { name },
    });
  }

  async findAll() {
    // 1. Отримуємо міста та їхніх менеджерів + кількість шкіл
    const cities = await this.prisma.city.findMany({
      orderBy: { createdAt: 'desc' },
      include: {
        users: {
          where: { role: 'MANAGER' },
          select: { id: true, name: true, phone: true },
          take: 1,
        },
        _count: { select: { schools: true } }, // <-- Додано цей рядок для підрахунку
      },
    });

    // 2. Рахуємо події через швидке агрегування (SQL GROUP BY) за мілісекунди
    const eventsStats = await this.prisma.event.groupBy({
      by: ['cityId', 'status'],
      _count: { _all: true },
    });

    // 3. Формуємо результат для клієнта
    return cities.map((city) => {
      // Вибираємо статистику лише для поточного міста
      const cityStats = eventsStats.filter((stat) => stat.cityId === city.id);

      const completedEvents = cityStats
        .filter((s) => s.status === 'RE_SALE')
        .reduce((sum, s) => sum + s._count._all, 0);

      const plannedEvents = cityStats
        .filter((s) => s.status !== 'RE_SALE')
        .reduce((sum, s) => sum + s._count._all, 0);

      return {
        ...city,
        manager: city.users[0] || null,
        plannedEvents,
        completedEvents,
        schoolsCount: city._count.schools, // <-- Віддаємо на фронтенд
      };
    });
  }
  async createCrew(
    cityId: string,
    data: { name: string; hostId: string; driverId: string },
  ) {
    const driver = await this.prisma.user.findUnique({
      where: { id: data.driverId },
    });
    return this.prisma.crew.create({
      data: {
        cityId,
        name: data.name,
        hostId: data.hostId,
        driverId: data.driverId,
        car: driver?.car || null,
        phone: driver?.phone || null,
      },
      include: { host: true, driver: true },
    });
  }

  async deleteCrew(id: string) {
    // Відв'язуємо екіпаж від подій перед видаленням, щоб не було помилок бази
    await this.prisma.event.updateMany({
      where: { crewId: id },
      data: { crewId: null },
    });
    return this.prisma.crew.delete({ where: { id } });
  }

  async findOne(id: string) {
    const city = await this.prisma.city.findUnique({
      where: { id },
      include: {
        users: {
          where: { role: 'MANAGER' },
          select: { id: true, name: true, phone: true },
          take: 1,
        },
        events: {
          where: { status: 'RE_SALE' },
          include: {
            school: { select: { id: true, name: true, type: true } },
            report: true,
            history: { orderBy: { createdAt: 'asc' } }, // ДОДАНО: підтягуємо історію пайплайну
          },
          orderBy: { date: 'desc' },
        },
        crews: {
          include: {
            host: { select: { id: true, name: true } },
            driver: { select: { id: true, name: true } },
          },
        },
      },
    });

    if (!city) return null;

    return {
      ...city,
      manager: city.users[0] || null,
    };
  }
}

import { Controller, Get, Query, UseGuards } from '@nestjs/common';
import { DashboardService } from './dashboard.service';
import { AuthGuard } from '../auth/auth.guard';
import { CurrentUser } from '../auth/decorators/current-user.decorator';
import type { JwtUser } from '../auth/interfaces/jwt-user.interface';

@Controller('dashboard')
@UseGuards(AuthGuard)
export class DashboardController {
  constructor(private readonly dashboardService: DashboardService) {}

  @Get('summary')
  getSummary(
    @CurrentUser() user: JwtUser,
    @Query('cityId') cityId?: string,
  ) {
    // SUPERADMIN отримує citiesStats; cityId ігнорується для суперадміна
    const effectiveCityId = user.role === 'SUPERADMIN' ? undefined : cityId;
    return this.dashboardService.getSummary(effectiveCityId, user.role);
  }
}

import { Module } from '@nestjs/common';
import { DashboardController } from './dashboard.controller';
import { DashboardService } from './dashboard.service';
import { PrismaModule } from '../prisma/prisma.module';
import { AuthModule } from '../auth/auth.module';

@Module({
  imports: [PrismaModule, AuthModule],
  controllers: [DashboardController],
  providers: [DashboardService],
})
export class DashboardModule {}

import { Injectable } from '@nestjs/common';
import { Prisma } from '@prisma/client';
import { PrismaService } from '../prisma/prisma.service';

const PIPELINE_STAGES = [
  'BASE', 'FIRST_CONTACT', 'INTERESTED', 'PRE_APPROVAL',
  'DATE_CONFIRMED', 'PREPARATION', 'IN_PROGRESS', 'DONE', 'REPORT', 'RE_SALE',
];

const STALE_DAYS = 7;

@Injectable()
export class DashboardService {
  constructor(private prisma: PrismaService) {}

  private cache = new Map();
  private CACHE_TTL = 60_000; // 60 секунд

  async getSummary(cityId?: string, role?: string) {
    const key = `${cityId ?? 'all'}-${role ?? 'anon'}`;
    const cached = this.cache.get(key);
    if (cached && Date.now() - cached.ts < this.CACHE_TTL) {
      console.log(`[Dashboard] cache hit — ${key}`);
      return cached.data;
    }

    const t0 = Date.now();
    console.log(`[Dashboard] start — cityId=${cityId ?? 'all'} role=${role}`);

    const now        = new Date();
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const todayEnd   = new Date(todayStart);
    todayEnd.setDate(todayEnd.getDate() + 1);
    const upcomingEnd = new Date(todayStart);
    upcomingEnd.setDate(upcomingEnd.getDate() + 6);

    const staleThreshold = new Date(now);
    staleThreshold.setDate(staleThreshold.getDate() - STALE_DAYS);

    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);
    const monthEnd   = new Date(now.getFullYear(), now.getMonth() + 1, 0, 23, 59, 59);

    const cityFilter   = cityId ? { cityId } : {};
    const isSuperAdmin = role === 'SUPERADMIN';

    const t1 = Date.now();
    const [
      todayEvents,
      upcomingEvents,
      funnelRows,
      monthEvents,
      staleSchoolsRaw,
      recentActivity,
    ] = await Promise.all([

      this.prisma.event.findMany({
        where: { ...cityFilter, date: { gte: todayStart, lt: todayEnd } },
        include: {
          school: { select: { id: true, name: true } },
          city:   { select: { id: true, name: true } },
          crew: {
            include: {
              host:   { select: { id: true, name: true } },
              driver: { select: { id: true, name: true } },
            },
          },
        },
        orderBy: { time: 'asc' },
      }),

      this.prisma.event.findMany({
        where: { ...cityFilter, date: { gte: todayEnd, lt: upcomingEnd } },
        include: {
          school: { select: { id: true, name: true } },
          city:   { select: { id: true, name: true } },
          crew: {
            include: {
              host:   { select: { id: true, name: true } },
              driver: { select: { id: true, name: true } },
            },
          },
        },
        orderBy: [{ date: 'asc' }, { time: 'asc' }],
        take: 8,
      }),

      cityId
        ? this.prisma.$queryRaw<{ status: string; count: bigint }[]>(Prisma.sql`
            SELECT COALESCE(e.status::text, 'BASE') as status, COUNT(*) as count
            FROM "School" s
            LEFT JOIN LATERAL (
              SELECT status FROM "Event"
              WHERE "schoolId" = s.id
              ORDER BY date DESC
              LIMIT 1
            ) e ON true
            WHERE s."cityId" = ${cityId}
            GROUP BY e.status
          `)
        : this.prisma.$queryRaw<{ status: string; count: bigint }[]>(Prisma.sql`
            SELECT COALESCE(e.status::text, 'BASE') as status, COUNT(*) as count
            FROM "School" s
            LEFT JOIN LATERAL (
              SELECT status FROM "Event"
              WHERE "schoolId" = s.id
              ORDER BY date DESC
              LIMIT 1
            ) e ON true
            GROUP BY e.status
          `),

      this.prisma.event.findMany({
        where: {
          ...cityFilter,
          status: { in: ['DONE', 'REPORT', 'RE_SALE'] },
          date:   { gte: monthStart, lte: monthEnd },
        },
        select: {
          id: true,
          report: {
            select: { totalSum: true, remainderSum: true, childrenCount: true },
          },
        },
      }),

      this.prisma.school.findMany({
        where: {
          ...cityFilter,
          events: {
            some: {
              status: { notIn: ['DONE', 'REPORT', 'RE_SALE'] },
              history: { every: { createdAt: { lt: staleThreshold } } },
            },
          },
        },
        include: {
          events: {
            where: { status: { notIn: ['DONE', 'REPORT', 'RE_SALE'] } },
            orderBy: { date: 'desc' },
            take: 1,
            include: {
              history: {
                orderBy: { createdAt: 'desc' },
                take: 1,
                select: { createdAt: true },
              },
            },
          },
        },
        take: 10,
      }),

      this.prisma.eventHistory.findMany({
        where: {
          createdAt: { gte: todayStart },
          ...(cityId ? { event: { cityId } } : {}),
        },
        include: {
          event: {
            select: {
              id:     true,
              school: { select: { id: true, name: true } },
            },
          },
        },
        orderBy: { createdAt: 'desc' },
        take: 20,
      }),
    ]);
    console.log(`[Dashboard] main Promise.all: ${Date.now() - t1}ms`);

    let citiesStats: {
      cityId:       string;
      cityName:     string;
      schoolsCount: number;
      activeEvents: number;
      monthRevenue: number;
    }[] = [];

    if (isSuperAdmin) {
      const t2 = Date.now();
      const [allCities, allSchools, allActiveEvents, allMonthEvents] =
        await Promise.all([
          this.prisma.city.findMany({ select: { id: true, name: true } }),
          this.prisma.school.groupBy({ by: ['cityId'], _count: { id: true } }),
          this.prisma.event.groupBy({
            by: ['cityId'],
            where: { status: { in: ['DATE_CONFIRMED', 'PREPARATION', 'IN_PROGRESS'] } },
            _count: { id: true },
          }),
          this.prisma.event.findMany({
            where: {
              status: { in: ['DONE', 'REPORT', 'RE_SALE'] },
              date:   { gte: monthStart, lte: monthEnd },
            },
            select: {
              cityId: true,
              report: { select: { totalSum: true } },
            },
          }),
        ]);
      console.log(`[Dashboard] superadmin queries: ${Date.now() - t2}ms`);

      const schoolsIdx = Object.fromEntries(allSchools.map(r => [r.cityId, r._count.id]));
      const activeIdx  = Object.fromEntries(allActiveEvents.map(r => [r.cityId, r._count.id]));
      const revenueIdx: Record = {};
      for (const ev of allMonthEvents) {
        revenueIdx[ev.cityId] = (revenueIdx[ev.cityId] ?? 0) + (ev.report?.totalSum ?? 0);
      }

      citiesStats = allCities
        .map(city => ({
          cityId:       city.id,
          cityName:     city.name,
          schoolsCount: schoolsIdx[city.id] ?? 0,
          activeEvents: activeIdx[city.id]  ?? 0,
          monthRevenue: revenueIdx[city.id] ?? 0,
        }))
        .sort((a, b) => b.monthRevenue - a.monthRevenue);
    }

    const funnel: Record = {};
    for (const stage of PIPELINE_STAGES) funnel[stage] = 0;
    let totalSchools = 0;
    for (const row of funnelRows) {
      const status = row.status ?? 'BASE';
      const count  = Number(row.count);
      if (funnel[status] !== undefined) funnel[status] += count;
      totalSchools += count;
    }

    const monthlyKpi = monthEvents.reduce(
      (acc, ev) => {
        acc.revenue  += ev.report?.totalSum      ?? 0;
        acc.profit   += ev.report?.remainderSum  ?? 0;
        acc.children += ev.report?.childrenCount ?? 0;
        acc.count    += 1;
        return acc;
      },
      { revenue: 0, profit: 0, children: 0, count: 0 },
    );

    const staleSchools = staleSchoolsRaw
      .map(school => {
        const lastHistory  = school.events[0]?.history[0];
        const lastActivity = lastHistory?.createdAt ?? null;
        const daysStale    = lastActivity
          ? Math.floor((now.getTime() - new Date(lastActivity).getTime()) / 86_400_000)
          : null;
        return {
          id:          school.id,
          name:        school.name,
          status:      school.events[0]?.status ?? null,
          lastActivity,
          daysStale,
        };
      })
      .sort((a, b) => (b.daysStale ?? 0) - (a.daysStale ?? 0));

    const activityFeed = recentActivity.map(h => ({
      id:         h.id,
      userName:   h.userName,
      role:       h.role,
      action:     h.action,
      comment:    h.comment,
      createdAt:  h.createdAt,
      schoolId:   h.event?.school?.id   ?? null,
      schoolName: h.event?.school?.name ?? null,
      eventId:    h.event?.id           ?? null,
    }));

    console.log(`[Dashboard] total: ${Date.now() - t0}ms`);

    const result = {
      todayEvents,
      upcomingEvents,
      funnel,
      totalSchools,
      monthlyKpi,
      staleSchools,
      activityFeed,
      citiesStats,
    };

    this.cache.set(key, { data: result, ts: Date.now() });
    return result;
  }
}

export class CreateEventDto {
  cityId: string;
  schoolId: string;

  project: string;

  date: string;
  time?: string;

  childrenPlanned?: number;

  price?: number;

  paymentMethod?: string;

  address?: string;

  contactPerson?: string;

  contactPhone?: string;

  equipment?: string;

  nextProject?: string;

  responsibleId?: string;
}

export class SubmitReportDto {
  announcementDone: boolean;
  materialShown: boolean;

  childrenCount: number;
  classesCount: number;
  privilegedCount: number;
  showingsCount: number;

  totalSum: number;
  schoolSum: number;

  expenses: any[];

  remainderSum: number;

  rating?: number;

  salaries: { userId: string; name: string; amount: number }[];
}

import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { PrismaService } from '../prisma/prisma.service';
import { TelegramService } from '../telegram/telegram.service';

@Injectable()
export class EventsSchedulerService implements OnModuleInit {
  private readonly logger = new Logger(EventsSchedulerService.name);

  constructor(
    private prisma: PrismaService,
    private telegramService: TelegramService,
  ) {}

  onModuleInit() {
    // Запускаємо перевірку один раз при старті, а потім кожні 24 години
    this.scheduleDailyCheck();
  }

  private scheduleDailyCheck() {
    const check = async () => {
      this.logger.log('Автоматична перевірка подій на завтра...');
      await this.checkEventsForTomorrow();
    };

    // Перевіряємо відразу при запуску
    check();

    // Запускаємо інтервал: 24 години = 24 * 60 * 60 * 1000 мс
    setInterval(check, 24 * 60 * 60 * 1000);
  }

  async checkEventsForTomorrow() {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);

    const startOfTomorrow = new Date(tomorrow.setHours(0, 0, 0, 0));
    const endOfTomorrow = new Date(tomorrow.setHours(23, 59, 59, 999));

    const events = await this.prisma.event.findMany({
      where: {
        date: { gte: startOfTomorrow, lte: endOfTomorrow },
        status: { not: 'RE_SALE' }
      },
      include: {
        crew: { include: { host: true, driver: true } },
        school: true,
        city: true
      }
    });

    for (const event of events) {
      if (event.crew) {
        await this.sendReminder(event, event.crew.host, 'ведучий');
        await this.sendReminder(event, event.crew.driver, 'водій');
      }
    }
  }

  private async sendReminder(event: any, user: any, roleLabel: string) {
    if (!user || (!user.telegramChatId && !user.telegramId)) return;

    const chatId = user.telegramChatId || user.telegramId;
    const message = `🔔 Нагадування про подію!\n\n` +
      `👤 Роль: ${roleLabel}\n` +
      `📅 Дата: завтра\n` +
      `🏫 Заклад: ${event.school?.name || '—'}\n` +
      `🎪 Проєкт: ${event.project}\n` +
      `📞 Контакт: ${event.contactPhone || '—'}`;

    try {
      await this.telegramService.sendMessage(chatId, message);
    } catch (e) {
      this.logger.error(`Помилка відправки: ${e}`);
    }
  }
}

