            {done} з {base} шкіл дійшли до проведення події



        {/* Стадії */}


          {PIPELINE_STAGES.map((stage) => {
            const count    = funnel[stage.key] ?? 0;
            const barWidth = Math.round((count / maxCount) * 100);

            return (
               navigate('/schools')}
                className="flex items-center gap-3 group w-full text-left"
