  PREPARATION:    'Підготовка',
  IN_PROGRESS:    'Подія в роботі',
};

interface Tier {
  label:    string;
  emoji:    string;
  min:      number;
  max:      number;
  dot:      string;   // колір крапки
  badge:    string;   // badge bg+text
  bar:      string;   // колір прогрес-бару
  row:      string;   // hover bg рядка
}

const TIERS: Tier[] = [
  {
    label: 'Критично',   emoji: '🔴',
    min: 21, max: Infinity,
    dot:   'bg-red-500',
    badge: 'bg-red-100 text-red-700 border border-red-200',
    bar:   'bg-red-500',
    row:   'hover:bg-red-50/40',
  },
  {
    label: 'Небезпечно', emoji: '🟠',
    min: 14, max: 20,
    dot:   'bg-orange-400',
    badge: 'bg-orange-100 text-orange-700 border border-orange-200',
    bar:   'bg-orange-400',
    row:   'hover:bg-orange-50/40',
  },
  {
    label: 'Увага',      emoji: '🟡',
    min: 7, max: 13,
    dot:   'bg-amber-400',
    badge: 'bg-amber-100 text-amber-700 border border-amber-200',
    bar:   'bg-amber-400',
    row:   'hover:bg-amber-50/30',
  },
];

function getTier(days: number): Tier {
  return TIERS.find(t => days >= t.min && days <= t.max) ?? TIERS[2];
}

// Нормалізуємо дні у відсотки для прогрес-бару (макс = 30 днів)
function barWidth(days: number): number {
  return Math.min(100, Math.round((days / 30) * 100));
}

