import { useState } from 'react';
import { api } from '../../../config/api';

interface Employee {
  id: string;
  name: string;
  role: string;
}

interface IssueModalProps {
  isOpen: boolean;
  onClose: () => void;
  schoolName: string;
  eventName: string;
  eventId: string;
  cityId: string;
  employees?: Employee[];
}

export default function IssueModal({
  isOpen, onClose, schoolName, eventName, eventId, cityId, employees = []
}: IssueModalProps) {
  const [message, setMessage] = useState('');
  const [deadline, setDeadline] = useState('');
  const [assignedUserId, setAssignedUserId] = useState('');
  const [isSending, setIsSending] = useState(false);
  const [sent, setSent] = useState(false);

  if (!isOpen) return null;

  const assignedUser = employees.find(e => e.id === assignedUserId);

  const handleSend = async () => {
    if (!message.trim()) return;
    setIsSending(true);
    try {
      await api.post('/issues', {
        eventId,
        schoolName,
        eventName,
        message,
        cityId,
        deadline: deadline || undefined,
        assignedUserId: assignedUserId || undefined,
        assignedUserName: assignedUser?.name || undefined,
      });
      setSent(true);
      setTimeout(() => {
        setSent(false);
        setMessage('');
        setDeadline('');
        setAssignedUserId('');
        onClose();
      }, 1500);
    } catch (e) {
      console.error(e);
    } finally {
      setIsSending(false);
    }
  };

  return (










🚨 Запит

{schoolName}

{eventName}

          ✕




          {/* Опис проблеми */}
           setMessage(e.target.value)}
            placeholder="Опишіть проблему або запит..."
            className="w-full p-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-red-400 focus:outline-none resize-none h-32"
            autoFocus
          />

          {/* Дедлайн */}



              ⏰ Дедлайн (необов'язково)

             setDeadline(e.target.value)}
              min={new Date().toISOString().slice(0, 10)}
              className="w-full p-2.5 border border-slate-200 rounded-xl focus:ring-2 focus:ring-red-400 focus:outline-none text-sm"
            />


          {/* Відповідальний */}
          {employees.length > 0 && (



