function stalenessColor(days: number | null): string {
  if (days === null) return 'text-slate-400';
  if (days >= 21)   return 'text-red-500';
  if (days >= 14)   return 'text-orange-500';
  if (days >= 7)    return 'text-amber-500';
  return 'text-emerald-500';
}

