      if (token) {
        const payload = JSON.parse(atob(token.split(".")[1]));
        setUserRole(payload.role);
        if (payload.role === "MANAGER" && selectedCity?.id) {
          setFilterCityId(selectedCity.id);
        }
      }
    } catch (e) {
      console.error("Помилка парсингу токена", e);
    }
  }, [selectedCity]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const headers = {
          Authorization: `Bearer ${localStorage.getItem("token")}`,
        };
        // ДОДАНО: api.get("/projects") та projRes
        const [eventsRes, citiesRes, projRes] = await Promise.all([
          api.get("/events", { headers }),
          api.get("/cities", { headers }),
          api.get("/projects", { headers }),
        ]);
        setEvents(eventsRes.data);
        setCities(citiesRes.data);
        setProjects(projRes.data); // ДОДАНО
      } catch (error) {
        console.error("Помилка завантаження календаря", error);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, []);

  const nextMonth = () =>
    setCurrentDate(
      new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1),
    );
  const prevMonth = () =>
    setCurrentDate(
      new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1),
    );
  const today = () => {
    setCurrentDate(new Date());
    setSelectedMobileDate(new Date());
  };

  const getDaysInMonth = (year: number, month: number) =>
    new Date(year, month + 1, 0).getDate();
  const getFirstDayOfMonth = (year: number, month: number) => {
    let day = new Date(year, month, 1).getDay();
    return day === 0 ? 6 : day - 1;
  };

  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();
  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);

  const days = [];
  for (let i = 0; i < firstDay; i++) days.push(null);
