import { useEffect, useState } from "react";
import { api } from "../config/api";
import PhoneLink from "../components/PhoneLink";
import { useSelectedCity } from "../context/CityContext";

type Role = "MANAGER" | "DRIVER" | "HOST" | "SUPERADMIN" | "GUEST";

interface City {
  id: string;
  name: string;
}
interface User {
  id: string;
  name: string;
  phone: string | null;
  email: string;
  cityId: string | null;
  city?: City;
  role: Role;
  telegramId?: string | null;
  car?: string | null;
}
interface Project {
  id: string;
  name: string;
  color: string;
}

const ROLE_LABELS: Record = {
  MANAGER: "Менеджер",
  DRIVER: "Водій",
  HOST: "Ведучий",
  SUPERADMIN: "Суперадмін",
  GUEST: "Гість",
};
const ROLE_COLORS: Record = {
  MANAGER: "bg-blue-50 text-blue-700 border-blue-200",
  DRIVER: "bg-emerald-50 text-emerald-700 border-emerald-200",
  HOST: "bg-violet-50 text-violet-700 border-violet-200",
};
const ROLE_HEADER_COLORS: Record = {
  MANAGER: "bg-blue-600",
  DRIVER: "bg-emerald-600",
  HOST: "bg-violet-600",
};
const EMPTY_FORM = {
  fullName: "",
  phone: "",
  email: "",
  cityId: "",
  role: "MANAGER" as Role,
  password: "",
  telegramId: "",
  car: "",
};

const PROJECT_COLORS: Record = {
  blue: "bg-blue-500",
  emerald: "bg-emerald-500",
  rose: "bg-rose-500",
  red: "bg-red-500",
  amber: "bg-amber-500",
  purple: "bg-purple-500",
};

export default function Employees() {
  const [users, setUsers] = useState([]);
  const [cities, setCities] = useState([]);
  const [projects, setProjects] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState(null);
  const [form, setForm] = useState({ ...EMPTY_FORM });
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [isProjectModalOpen, setIsProjectModalOpen] = useState(false);
  const [projectForm, setProjectForm] = useState({ name: "", color: "blue" });

  const { selectedCity } = useSelectedCity();
  const token = localStorage.getItem("token");
  const headers = { Authorization: `Bearer ${token}` };

  const fetchData = async () => {
    // 1. Завантажуємо критичні дані (Працівники та Міста)
    try {
      const [usersRes, citiesRes] = await Promise.all([
        api.get("/users", { headers }),
        api.get("/cities", { headers }),
      ]);
      setUsers(usersRes.data);
      setCities(citiesRes.data);
    } catch (e) {
      console.error("Помилка завантаження працівників:", e);
    }

    // 2. Окремо завантажуємо проєкти (не критично для списку працівників)
    try {
      const projRes = await api.get("/projects", { headers });
      setProjects(projRes.data);
    } catch (e) {
      console.warn("Проєктів ще немає або помилка їх завантаження:", e);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const cityFilteredUsers = selectedCity.id
    ? users.filter((u) => u.cityId === selectedCity.id)
    : users;
  const grouped = (["MANAGER", "DRIVER", "HOST"] as Role[]).map((role) => ({
    role,
    label: ROLE_LABELS[role],
    items: cityFilteredUsers.filter((u) => u.role === role),
  }));

  const handleOpenModal = (user: User | null = null) => {
    setEditingUser(user);
    if (user) {
      setForm({
        fullName: user.name,
        phone: user.phone || "",
        email: user.email,
        cityId: user.cityId || "",
        role: user.role,
        password: "",
        telegramId: user.telegramId || "",
        car: user.car || "",
      });
    } else {
      setForm({ ...EMPTY_FORM });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.fullName.trim()) return;
    setIsSubmitting(true);
    try {
      if (editingUser)
        await api.patch(`/users/${editingUser.id}`, form, { headers });
      else await api.post("/users", form, { headers });
      setIsModalOpen(false);
      fetchData();
    } catch (e) {
      alert("Помилка збереження. Перевірте, чи не дублюється email.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async (id: string, name: string) => {
    if (!window.confirm(`Видалити користувача "${name}"?`)) return;
    try {
      await api.delete(`/users/${id}`, { headers });
      setUsers(users.filter((u) => u.id !== id));
    } catch (e) {
      alert("Помилка видалення");
    }
  };

  const handleCreateProject = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!projectForm.name.trim()) return;
    try {
      await api.post("/projects", projectForm, { headers });
      setIsProjectModalOpen(false);
      setProjectForm({ name: "", color: "blue" });
      fetchData();
    } catch (e) {
      alert("Помилка. Можливо такий вид події вже існує.");
    }
  };

  const handleDeleteProject = async (id: string, name: string) => {
    if (
      !window.confirm(
        `Видалити вид події "${name}"? Існуючі події з цією назвою збережуться.`,
      )
    )
      return;
    try {
      await api.delete(`/projects/${id}`, { headers });
      fetchData();
    } catch (e) {
      alert("Помилка видалення");
    }
  };

  return (








            Акаунти та Проєкти{" "}
            {selectedCity.id && (

                · {selectedCity.name}

            )}



            Керування доступами, працівниками та видами подій


         handleOpenModal()}
          className="bg-blue-600 text-white px-4 py-2.5 sm:py-2 rounded-lg font-medium hover:bg-blue-700 w-full sm:w-auto"
        >
          + Створити користувача





        {grouped.map(({ role, label, items }) => (







{label}

                {items.length}


            {items.length === 0 ? (


                Немає {label.toLowerCase()}ів

            ) : (






                      ПІБ
                      Телефон
                      Пошта / Логін
                      Місто
                      Дії



                    {items.map((u) => (







                              {u.name.charAt(0)}


                              {u.name}





                          {u.car && (


                              🚗 {u.car}

                          )}


                          {u.email}



                            📍 {u.city?.name || "Всі міста"}



                           handleOpenModal(u)}
                            className="text-slate-400 hover:text-blue-500 p-1.5 hover:bg-blue-50 mr-2"
                          >
                            ✏️

                           handleDelete(u.id, u.name)}
                            className="text-slate-400 hover:text-red-500 p-1.5 hover:bg-red-50"
